  "COMMUNES.PRIORITYDISCTRICT": {"server":"https://data.geopf.fr/wmts","key":"gpf","layer":"COMMUNES.PRIORITYDISCTRICT","title":"Quartiers prioritaires","format":"image/png","style":"normal","queryable":false,"tilematrix":"PM","minZoom":6,"maxZoom":17,"bbox":[-63.37252,-21.475586,55.925865,51.31212],"desc":"<![CDATA[<div style=\"text-align:justify;\">Les quartiers prioritaires de la politique de la ville sont issus de la loi de programmation pour la ville et cohésion urbaine n° 2014-173 du 21 février 2014.<br/>\n<div style=\"text-decoration:underline;\"><a href=\"http://www.ville.gouv.fr/?geographie-prioritaire-de-la\" alt=\"http://www.ville.gouv.fr/?geographie-prioritaire-de-la\">Téléchargement des données</a></div><br/>\nSources : Commissariat Général à l'Egalité des Territoires :  1er janvier 2015</div>]]>","originators":{"CGET":{"href":"http://www.cget.gouv.fr/","attribution":"Commissariat général à l'égalité des territoires","logo":"https://wxs.ign.fr/static/logos/CGET/CGET.gif","minZoom":7,"maxZoom":16,"constraint":[{"minZoom":7,"maxZoom":16,"bbox":[-63.37252,-21.475586,55.925865,51.31212]}]}}},
