  "PROTECTEDAREAS.RN": {"server":"https://data.geopf.fr/wmts","key":"gpf","layer":"PROTECTEDAREAS.RN","title":"Réserves naturelles nationales","format":"image/png","style":"normal","queryable":true,"tilematrix":"PM","minZoom":0,"maxZoom":16,"bbox":[-63.37252,-53.627914,82.645004,51.31212],"desc":"Les réserves naturelles sont des espaces protégés terrestres ou marins dont le patrimoine naturel est exceptionnel, tant sur le plan de la biodiversité que parfois sur celui de la géodiversité. 16-11-2021","originators":{"IGN":{"href":"https://www.ign.fr","attribution":"Institut national de l'information géographique et forestière","logo":"https://wxs.ign.fr/static/logos/IGN/IGN.gif","minZoom":0,"maxZoom":16,"constraint":[{"minZoom":0,"maxZoom":16,"bbox":[-63.37252,-53.627914,82.645004,51.31212]}]}}},
