  "ELEVATION.ELEVATIONGRIDCOVERAGE.THRESHOLD": {"server":"https://data.geopf.fr/wmts","key":"gpf","layer":"ELEVATION.ELEVATIONGRIDCOVERAGE.THRESHOLD","title":"Seuils de pente pour l'agriculture","format":"image/png","style":"ELEVATION.ELEVATIONGRIDCOVERAGE.THRESHOLD","queryable":false,"tilematrix":"PM","minZoom":3,"maxZoom":17,"bbox":[-5.1504726,41.32521,9.570543,51.099052],"desc":"La carte expérimentale des seuils de pente pour l'agriculture est dérivée du MNT RGEAlti, modèle numérique de terrain maillé au pas de 1 m. Les seuils de représentation de cette carte sont : 7% à 10% : bleu, 10% à 15% : mauve, 15% à 20% : orange, plus de 20% : rouge. Données disponibles en France Métropolitaine du 1/4265 au 1/69885283 - mise à jour du 30/06/2017.","originators":{"IGN":{"href":"https://www.ign.fr","attribution":"Institut national de l'information géographique et forestière","logo":"https://wxs.ign.fr/static/logos/IGN/IGN.gif","minZoom":3,"maxZoom":17,"constraint":[{"minZoom":3,"maxZoom":17,"bbox":[-5.1504726,41.32521,9.570543,51.099052]}]}}},  
